class $$StoresTableTableManager
    extends
        RootTableManager<
          _$AppDatabase,
          $StoresTable,
          Store,
          $$StoresTableFilterComposer,
          $$StoresTableOrderingComposer,
          $$StoresTableAnnotationComposer,
          $$StoresTableCreateCompanionBuilder,
          $$StoresTableUpdateCompanionBuilder,
          (Store, $$StoresTableReferences),
          Store,
          PrefetchHooks Function({
            bool categoriesRefs,
            bool itemsRefs,
            bool modifierGroupsRefs,
            bool customersRefs,
            bool loyaltySettingsRefs,
            bool employeeRolesRefs,
            bool employeesRefs,
            bool receiptsRefs,
            bool shiftsRefs,
            bool inventoryLevelsRefs,
            bool stockAdjustmentsRefs,
            bool inventoryCountsRefs,
            bool suppliersRefs,
            bool purchaseOrdersRefs,
            bool transferOrdersRefs,
            bool taxRatesRefs,
            bool expenseCategoriesRefs,
            bool expensesRefs,
            bool auditLogsRefs,
            bool settingsRefs,
          })
        > {
  $$StoresTableTableManager(_$AppDatabase db, $StoresTable table)
    : super(
        TableManagerState(
          db: db,
          table: table,
          createFilteringComposer: () =>
              $$StoresTableFilterComposer($db: db, $table: table),
          createOrderingComposer: () =>
              $$StoresTableOrderingComposer($db: db, $table: table),
          createComputedFieldComposer: () =>
              $$StoresTableAnnotationComposer($db: db, $table: table),
          updateCompanionCallback:
              ({
                Value<String> id = const Value.absent(),
                Value<String> name = const Value.absent(),
                Value<String> address = const Value.absent(),
                Value<String> phone = const Value.absent(),
                Value<String> currency = const Value.absent(),
                Value<String> timezone = const Value.absent(),
                Value<String?> logo = const Value.absent(),
                Value<String> secondaryCurrencies = const Value.absent(),
                Value<String> exchangeRates = const Value.absent(),
                Value<DateTime> createdAt = const Value.absent(),
                Value<DateTime> updatedAt = const Value.absent(),
                Value<int> rowid = const Value.absent(),
              }) => StoresCompanion(
                id: id,
                name: name,
                address: address,
                phone: phone,
                currency: currency,
                timezone: timezone,
                logo: logo,
                secondaryCurrencies: secondaryCurrencies,
                exchangeRates: exchangeRates,
                createdAt: createdAt,
                updatedAt: updatedAt,
                rowid: rowid,
              ),
          createCompanionCallback:
              ({
                required String id,
                required String name,
                Value<String> address = const Value.absent(),
                Value<String> phone = const Value.absent(),
                Value<String> currency = const Value.absent(),
                Value<String> timezone = const Value.absent(),
                Value<String?> logo = const Value.absent(),
                Value<String> secondaryCurrencies = const Value.absent(),
                Value<String> exchangeRates = const Value.absent(),
                Value<DateTime> createdAt = const Value.absent(),
                Value<DateTime> updatedAt = const Value.absent(),
                Value<int> rowid = const Value.absent(),
              }) => StoresCompanion.insert(
                id: id,
                name: name,
                address: address,
                phone: phone,
                currency: currency,
                timezone: timezone,
                logo: logo,
                secondaryCurrencies: secondaryCurrencies,
                exchangeRates: exchangeRates,
                createdAt: createdAt,
                updatedAt: updatedAt,
                rowid: rowid,
              ),
          withReferenceMapper: (p0) => p0
              .map(
                (e) =>
                    (e.readTable(table), $$StoresTableReferences(db, table, e)),
              )
              .toList(),
          prefetchHooksCallback:
              ({
                categoriesRefs = false,
                itemsRefs = false,
                modifierGroupsRefs = false,
                customersRefs = false,
                loyaltySettingsRefs = false,
                employeeRolesRefs = false,
                employeesRefs = false,
                receiptsRefs = false,
                shiftsRefs = false,
                inventoryLevelsRefs = false,
                stockAdjustmentsRefs = false,
                inventoryCountsRefs = false,
                suppliersRefs = false,
                purchaseOrdersRefs = false,
                transferOrdersRefs = false,
                taxRatesRefs = false,
                expenseCategoriesRefs = false,
                expensesRefs = false,
                auditLogsRefs = false,
                settingsRefs = false,
              }) {
                return PrefetchHooks(
                  db: db,
                  explicitlyWatchedTables: [
                    if (categoriesRefs) db.categories,
                    if (itemsRefs) db.items,
                    if (modifierGroupsRefs) db.modifierGroups,
                    if (customersRefs) db.customers,
                    if (loyaltySettingsRefs) db.loyaltySettings,
